import React from "react";
import "./Section.css";

function Medicine() {
  return (
    <div className="section-card">
      <div className="icon">💊</div>
      <h3>Medicine Delivery</h3>
      <p>Order prescribed medicines online and have them delivered to your doorstep.</p>
    </div>
  );
}

export default Medicine;
